    pub fn handle_error_message(&self, mut client: Value, mut message: Value) -> Value {
        //
        // generic error format
        //
        //     { "error": errorMessage }
        //
        // examples
        //
        //     {
        //         "status": 429,
        //         "error": "Rate limit exceeded, retry in 1 seconds.",
        //         "meta": { "retryAfter": 1 },
        //         "request": { "op": "subscribe", "args": "orderBook" },
        //     }
        //
        //     { "error": "Rate limit exceeded, retry in 29 seconds." }
        //
        let mut error: Value = self.safe_string_k(message.clone(), "error", &[]);
        if !is_equal(&error, &Value::Null) {
            let mut request: Value = self.safe_value_k(message.clone(), "request", &[Value::Map({
                let mut m = indexmap::IndexMap::new();
                m
            })]);
            let mut args: Value = self.safe_value_k(request.clone(), "args", &[Value::List(vec![])]);
            let mut numArgs: Value = get_array_length(&args);
            if is_greater_than(&numArgs, &Value::Int(0)) {
                let mut messageHash: Value = get_value(&args, &Value::Int(0));
                let mut broad: Value = get_value(&get_value(&self.exceptions, &Value::Str("ws".to_string())), &Value::Str("broad".to_string()));
                let mut broadKey: Value = self.find_broadly_matched_key(broad.clone(), error.clone());
                let mut exception: Value = Value::Null;
                if is_equal(&broadKey, &Value::Null) {
                    exception = Value::from(crate::exchange_errors::exchange_error(                    error)); // c# requirement for now
                }  else {
                    exception = Value::from(crate::exchange_errors::create_error(&crate::runtime::stringify_param(&(get_value(&broad, &broadKey))), &crate::runtime::stringify_param(&(error))));
                }
                client.reject(&[exception.clone(), messageHash.clone()]);
                return Value::Bool(false);
            }
        }
        return Value::Bool(true);

    Value::Null
}

    pub fn handle_message(&self, mut client: Value, mut message: Value) {
        //
        //     {
        //         "info": "Welcome to the BitMEX Realtime API.",
        //         "version": "2019-11-22T00:24:37.000Z",
        //         "timestamp": "2019-11-23T09:04:42.569Z",
        //         "docs": "https://www.bitmex.com/app/wsAPI",
        //         "limit": { remaining: 38 }
        //     }
        //
        //     {
        //         "success": true,
        //         "subscribe": "orderBookL2:XBTUSD",
        //         "request": { op: "subscribe", args: [ "orderBookL2:XBTUSD" ] }
        //     }
        //
        //     {
        //         "table": "orderBookL2",
        //         "action": "update",
        //         "data": [
        //             { symbol: "XBTUSD", id: 8799284800, side: "Sell", size: 721000 },
        //             { symbol: "XBTUSD", id: 8799285100, side: "Sell", size: 70590 },
        //             { symbol: "XBTUSD", id: 8799285550, side: "Sell", size: 217652 },
        //             { symbol: "XBTUSD", id: 8799285850, side: "Sell", size: 105578 },
        //             { symbol: "XBTUSD", id: 8799286350, side: "Sell", size: 172093 },
        //             { symbol: "XBTUSD", id: 8799286650, side: "Sell", size: 201125 },
        //             { symbol: "XBTUSD", id: 8799288950, side: "Buy", size: 47552 },
        //             { symbol: "XBTUSD", id: 8799289250, side: "Buy", size: 78217 },
        //             { symbol: "XBTUSD", id: 8799289700, side: "Buy", size: 193677 },
        //             { symbol: "XBTUSD", id: 8799290000, side: "Buy", size: 818161 },
        //             { symbol: "XBTUSD", id: 8799290500, side: "Buy", size: 218806 },
        //             { symbol: "XBTUSD", id: 8799290800, side: "Buy", size: 102946 }
        //         ]
        //     }
        //
        if is_true(&self.handle_error_message(client.clone(), message.clone())) {
            let mut table: Value = self.safe_string_k(message.clone(), "table", &[]);
            let mut methods: Value = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("orderBookL2".to_string(), Value::Null.clone());
                    m.insert("orderBookL2_25".to_string(), Value::Null.clone());
                    m.insert("orderBook10".to_string(), Value::Null.clone());
                    m.insert("instrument".to_string(), Value::Null.clone());
                    m.insert("trade".to_string(), Value::Null.clone());
                    m.insert("tradeBin1m".to_string(), Value::Null.clone());
                    m.insert("tradeBin5m".to_string(), Value::Null.clone());
                    m.insert("tradeBin1h".to_string(), Value::Null.clone());
                    m.insert("tradeBin1d".to_string(), Value::Null.clone());
                    m.insert("order".to_string(), Value::Null.clone());
                    m.insert("execution".to_string(), Value::Null.clone());
                    m.insert("margin".to_string(), Value::Null.clone());
                    m.insert("liquidation".to_string(), Value::Null.clone());
                    m.insert("position".to_string(), Value::Null.clone());
                m
            });
            let mut method: Value = self.safe_value(methods.clone(), table.clone(), &[]);
            if is_equal(&method, &Value::Null) {
                let mut request: Value = self.safe_value_k(message.clone(), "request", &[Value::Map({
                    let mut m = indexmap::IndexMap::new();
                    m
                })]);
                let mut op: Value = self.safe_value_k(request.clone(), "op", &[]);
                if is_equal(&op, &Value::Str("authKeyExpires".to_string())) {
                    self.handle_authentication_message(client.clone(), message.clone());
                }
            }  else {
                method.call(&[client.clone(), message.clone()]);
            }
        }
}
